// ── Plan selection ──
let selectedPlan = 'annual';

function selectPlan(plan) {
  selectedPlan = plan;
  document.querySelectorAll('.plan-option').forEach(el => {
    el.classList.toggle('selected', el.dataset.plan === plan);
  });
}

// ── Open JOIN NOW modal with correct plan content ──
const planData = {
  monthly: {
    tag: 'NLCA Membership · Monthly',
    title: 'Join Next Level Case Acceptance',
    price: '$295',
    period: 'billed monthly · cancel anytime',
    save: '',
    extraItem: 'Cancel anytime — no contracts',
    checkout: 'https://link.fastpaydirect.com/payment-link/69c59f67c6a0e600f4d05b91'
  },
  annual: {
    tag: 'NLCA Membership · Annual',
    title: 'Join Next Level Case Acceptance',
    price: '$2,950',
    period: 'billed annually',
    save: 'Save $590 vs monthly',
    extraItem: 'Locked-in rate for 12 months',
    checkout: 'https://link.fastpaydirect.com/payment-link/69c5a02ac6a0e600f4d05b94'
  }
};

function openPlanModal() {
  const d = planData[selectedPlan];
  document.getElementById('modalTag').textContent = d.tag;
  document.getElementById('modalTitle').textContent = d.title;
  document.getElementById('modalPrice').textContent = d.price;
  document.getElementById('modalPeriodSub').textContent = d.period;
  document.getElementById('modalSaveNote').textContent = d.save;
  document.getElementById('modalExtraItem').textContent = d.extraItem;
  document.getElementById('planModal').classList.add('open');
  document.body.style.overflow = 'hidden';
}

function proceedToCheckout() {
  const url = planData[selectedPlan].checkout;
  window.open(url, '_blank');
}

// ── Open Discovery Call modal ──
function openDiscoveryModal() {
  document.getElementById('discoveryModal').classList.add('open');
  document.body.style.overflow = 'hidden';
}

function handleDiscoverySubmit(e) {
  e.preventDefault();
  const btn = e.target.querySelector('button[type="submit"]');
  btn.textContent = '✓ REQUEST RECEIVED — WE\'LL BE IN TOUCH';
  btn.style.background = '#0F4FB5';
  btn.disabled = true;
  // Wire to your GHL webhook here
}

// ── Close modals ──
function closeModal(id) {
  document.getElementById(id).classList.remove('open');
  document.body.style.overflow = '';
}
function closeOnOverlay(e, id) {
  if (e.target === document.getElementById(id)) closeModal(id);
}
document.addEventListener('keydown', e => {
  if (e.key === 'Escape') {
    closeModal('planModal');
    closeModal('discoveryModal');
  }
});

// ── Opt-in form ──
function handleSubmit(e) {
  e.preventDefault();
  const btn = e.target.querySelector('button[type="submit"]');
  btn.textContent = '✓ CHECK YOUR INBOX';
  btn.style.background = '#0F4FB5';
  btn.disabled = true;
  // Wire to your GHL webhook URL here
}

// ── Mobile menu ──
function toggleMenu() {
  const btn = document.getElementById('hamburger');
  const menu = document.getElementById('mobileMenu');
  btn.classList.toggle('open');
  menu.classList.toggle('open');
  document.body.style.overflow = menu.classList.contains('open') ? 'hidden' : '';
}

// ── Full-width: break out of any GHL parent container ──
(function() {
  function forceFullWidth() {
    // Walk all ancestors of body and strip width constraints
    var el = document.body;
    while (el) {
      el.style.setProperty('max-width', 'none', 'important');
      el.style.setProperty('padding-left', '0', 'important');
      el.style.setProperty('padding-right', '0', 'important');
      el.style.setProperty('margin-left', '0', 'important');
      el.style.setProperty('margin-right', '0', 'important');
      el.style.setProperty('width', '100%', 'important');
      el = el.parentElement;
    }
    // Also force the page root breakout
    var root = document.getElementById('page-root');
    if (root) {
      root.style.setProperty('width', '100vw', 'important');
      root.style.setProperty('max-width', '100vw', 'important');
      root.style.setProperty('position', 'relative', 'important');
      root.style.setProperty('left', '50%', 'important');
      root.style.setProperty('margin-left', '-50vw', 'important');
      root.style.setProperty('margin-right', '-50vw', 'important');
    }
  }
  forceFullWidth();
  window.addEventListener('load', forceFullWidth);
  // Run again after a short delay for GHL's lazy-loaded layout
  setTimeout(forceFullWidth, 300);
  setTimeout(forceFullWidth, 800);
})();

// ── Smooth scroll ──
document.querySelectorAll('a[href^="#"]').forEach(a => {
  a.addEventListener('click', e => {
    const target = document.querySelector(a.getAttribute('href'));
    if (target) { e.preventDefault(); target.scrollIntoView({ behavior: 'smooth', block: 'start' }); }
  });
});

