    }
    .about-left h2 {
      font-size: clamp(30px, 3.5vw, 44px);
      font-weight: 800;
      color: #fff;
      line-height: 1.18;
      margin-bottom: 24px;
    }
    .about-left h2 em { color: var(--azure); font-style: normal; }
    .about-left p {
      font-size: 17px;
      color: var(--muted);
      line-height: 1.78;
      margin-bottom: 20px;
    }
    .about-creds {
      margin: 28px 0;
      display: flex;
      flex-direction: column;
      gap: 12px;
    }
    .about-cred {
      display: flex;
      align-items: center;
      gap: 12px;
      font-size: 15px;
      font-weight: 600;
      color: rgba(255,255,255,0.85);
    }
    .cred-icon {
      width: 28px; height: 28px;
      background: rgba(22,103,232,0.15);
      border-radius: 50%;
      display: flex; align-items: center; justify-content: center;
      font-size: 13px;
      color: var(--gold);
      flex-shrink: 0;
    }
    .about-photo {
      background: var(--navy2);
      border: 1px solid rgba(22,103,232,0.2);
      border-radius: 20px;
      aspect-ratio: 4/5;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 14px;
      color: rgba(255,255,255,0.25);
      text-align: center;
      padding: 24px;
    }

    /* ─── SERVICES ─── */
    #services {
      background: var(--navy);
      padding: 90px 0;
    }
    .services-grid {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 24px;
    }
    .scard {
      background: var(--navy2);
      border: 1px solid rgba(255,255,255,0.07);
      border-radius: 14px;
      padding: 36px 30px;
      transition: border-color .2s, transform .2s;
      position: relative;
      overflow: hidden;
    }
    .scard:hover { border-color: rgba(22,103,232,0.4); transform: translateY(-4px); }
    .scard.featured {
      border-color: rgba(22,103,232,0.5);
      background: linear-gradient(145deg, #0d0d30 0%, #0a0a28 100%);
    }
    .scard.featured::before {
      content: 'FLAGSHIP';
      position: absolute;
      top: 16px; right: -30px;
      background: var(--azure);
      color: #fff;
      font-size: 9px;
      font-weight: 800;
      letter-spacing: 1.5px;
      padding: 5px 44px;
      transform: rotate(45deg);
    }
    .scard-icon {
      font-size: 28px;
      margin-bottom: 18px;
      display: block;
    }
    .scard-tag {
      font-size: 11px;
      font-weight: 700;
      letter-spacing: 2px;
      text-transform: uppercase;
      color: var(--azure);
      margin-bottom: 10px;
      display: block;
    }
    .scard h3 {
      font-size: 20px;
      font-weight: 800;
      color: #fff;
      margin-bottom: 12px;
      line-height: 1.3;
    }
    .scard p {
      font-size: 14px;
      color: var(--muted);
      line-height: 1.7;
      margin-bottom: 18px;
    }
    .scard-price {
      font-size: 26px;
      font-weight: 900;
      color: var(--azure);
      margin-bottom: 18px;
    }
    .scard-price sub { font-size: 14px; font-weight: 600; color: var(--muted); }
    .scard-bullets {
      list-style: none;
      margin-bottom: 22px;
    }
    .scard-bullets li {
      font-size: 13px;
      color: rgba(255,255,255,0.70);
      padding: 5px 0 5px 20px;
      position: relative;
    }
    .scard-bullets li::before {
      content: '✓';
      position: absolute; left: 0;
      color: var(--azure);
      font-weight: 700;
    }
    .scard-link {
      font-size: 14px;
      font-weight: 700;
      color: var(--azure);
      text-decoration: none;
      letter-spacing: 0.3px;
    }
    .scard-link:hover { text-decoration: underline; }
    .scard .btn-primary { font-size: 14px; padding: 12px 22px; }

    /* ─── NLCA FEATURE ─── */
    #nlca {
      background: var(--charcoal);
      padding: 90px 0;
    }
    .nlca-inner {
      background: var(--navy2);
      border: 1px solid rgba(22,103,232,0.30);
      border-radius: 20px;
      padding: 60px 56px;
      display: grid;
      grid-template-columns: 1fr 360px;
      gap: 60px;
      align-items: center;
    }
    .nlca-left h2 {
      font-size: clamp(28px, 3vw, 40px);
      font-weight: 900;
      color: #fff;
      line-height: 1.18;
      margin-bottom: 18px;
    }
    .nlca-left h2 em { color: var(--azure); font-style: normal; }
    .nlca-left p {
      font-size: 16px;
      color: var(--muted);
      line-height: 1.75;
      margin-bottom: 28px;
    }
    .nlca-modules {
      display: flex;
      flex-direction: column;
      gap: 10px;
      margin-bottom: 32px;
    }
    .nlca-module {
      display: flex;
      align-items: flex-start;
      gap: 14px;
      font-size: 14px;
      color: rgba(255,255,255,0.80);
    }
    .module-num {
      font-size: 12px;
      font-weight: 800;
      color: var(--azure);
      background: rgba(22,103,232,0.12);
      border-radius: 4px;
      padding: 3px 8px;
      flex-shrink: 0;
      margin-top: 1px;
    }
    .nlca-pricing-card {
      background: var(--navy);
      border: 1px solid rgba(22,103,232,0.25);
      border-radius: 14px;
      padding: 36px 32px;
      text-align: center;
    }
    .nlca-pricing-card h4 {
      font-size: 16px;
      font-weight: 700;
      color: rgba(255,255,255,0.7);
      margin-bottom: 24px;
    }
    .nlca-price-row {
      display: flex;
      flex-direction: column;
      gap: 16px;
      margin-bottom: 28px;
    }
    .nlca-price {
      padding: 20px;
      border-radius: 10px;
      border: 1px solid rgba(255,255,255,0.08);
    }
    .nlca-price.recommended {
      border-color: rgba(22,103,232,0.5);
      background: rgba(22,103,232,0.08);
      position: relative;
    }
    .nlca-price.recommended::before {
      content: 'BEST VALUE';
      position: absolute;
      top: -10px; left: 50%;
      transform: translateX(-50%);
      background: var(--azure);
      color: #fff;
      font-size: 9px;
      font-weight: 800;
      letter-spacing: 1.5px;
      padding: 3px 12px;
      border-radius: 20px;
    }
    .nlca-price-amount {
      font-size: 36px;
      font-weight: 900;
      color: var(--white);
      line-height: 1;
      margin-bottom: 4px;
    }
    .nlca-price-period {
      font-size: 13px;
      color: var(--muted);
    }
    .nlca-price-save {
      font-size: 12px;
      color: var(--gold);
      font-weight: 700;
      margin-top: 4px;
    }
    .nlca-pricing-card .btn-primary { width: 100%; text-align: center; margin-bottom: 12px; }
    .nlca-pricing-card .btn-ghost { width: 100%; text-align: center; font-size: 14px; padding: 13px 20px; }

    /* ─── TRAINING METHODS ─── */
    #training {
      background: var(--navy);
      padding: 90px 0;
    }
    .training-grid {
      display: grid;
      grid-template-columns: repeat(4, 1fr);
      gap: 20px;
    }
    .tcard {
      background: var(--navy2);
      border: 1px solid rgba(255,255,255,0.06);
      border-radius: 12px;
      padding: 32px 24px;
      text-align: center;
      transition: border-color .2s;
    }
    .tcard:hover { border-color: rgba(22,103,232,0.3); }
    .tcard-icon { font-size: 32px; margin-bottom: 16px; display: block; }
    .tcard h3 { font-size: 17px; font-weight: 800; color: #fff; margin-bottom: 10px; }
    .tcard p { font-size: 13px; color: var(--muted); line-height: 1.65; }

    /* ─── MODULES ─── */
    #modules {
      background: var(--charcoal);
      padding: 90px 0;
    }
    .modules-grid {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 20px;
    }
    .mcard {
      background: var(--navy2);
      border: 1px solid rgba(255,255,255,0.06);
      border-left: 3px solid var(--azure);
      border-radius: 12px;
      padding: 30px 26px;
      transition: transform .2s;
    }
    .mcard:hover { transform: translateY(-3px); }
    .mcard-num {
      font-size: 42px;
      font-weight: 900;
      color: rgba(22,103,232,0.20);
      line-height: 1;
      margin-bottom: 4px;
    }
    .mcard h3 { font-size: 18px; font-weight: 800; color: #fff; margin-bottom: 10px; }
    .mcard p { font-size: 13px; color: var(--muted); line-height: 1.65; }
    .modules-mid-cta { text-align: center; grid-column: 1 / -1; padding: 8px 0; }

    /* ─── PAIN ─── */
    #pain {
      background: var(--navy);
      padding: 90px 0;
    }
    .pain-grid {
      display: grid;
      grid-template-columns: repeat(5, 1fr);
      gap: 16px;
      margin-bottom: 52px;
    }
    .pain-card {
      background: var(--navy2);
      border: 1px solid rgba(255,255,255,0.06);
      border-radius: 12px;
      padding: 28px 18px;
      text-align: center;
      transition: border-color .2s;
    }
    .pain-card:hover { border-color: rgba(22,103,232,0.35); }
    .pain-icon { font-size: 26px; margin-bottom: 10px; display: block; }
    .pain-card p { font-size: 14px; font-weight: 600; color: #fff; line-height: 1.4; }
    .pain-bridge {
      max-width: 700px;
      margin: 0 auto;
      text-align: center;
    }
    .pain-quote {
      font-size: 19px;
      color: var(--muted);
      line-height: 1.75;
      font-style: italic;
      margin-bottom: 10px;
    }
    .pain-quote strong { color: #fff; font-style: normal; }
    .pain-attr { font-size: 13px; font-weight: 700; color: var(--azure); margin-bottom: 32px; display: block; }

    /* ─── TESTIMONIALS ─── */
    #testimonials {
      background: var(--charcoal);
      padding: 90px 0;
    }
    .testi-grid {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 20px;
    }
    .tc {
      background: var(--navy2);
      border: 1px solid rgba(255,255,255,0.06);
      border-radius: 14px;
      padding: 32px 28px;
    }
    .tc-stars { color: var(--gold); font-size: 15px; letter-spacing: 2px; margin-bottom: 14px; }
    .tc-quote { font-size: 14px; color: var(--muted); line-height: 1.72; font-style: italic; margin-bottom: 22px; }
    .tc-author { display: flex; align-items: center; gap: 12px; }
    .tc-avatar {
      width: 42px; height: 42px;
      border-radius: 50%;
      background: rgba(22,103,232,0.15);
      border: 1px solid rgba(22,103,232,0.3);
      display: flex; align-items: center; justify-content: center;
      font-size: 15px; font-weight: 800; color: var(--azure);
      flex-shrink: 0;
    }
    .tc-name { font-size: 14px; font-weight: 700; color: #fff; }
    .tc-role { font-size: 12px; color: rgba(255,255,255,0.4); }

    .stat-banner {
      background: var(--azure);
      border-radius: 14px;
      padding: 44px 48px;
      text-align: center;
      margin-top: 36px;
    }
    .stat-banner-num {
      font-size: 76px;
      font-weight: 900;
      color: #fff;
      line-height: 1;
    }
    .stat-banner-label {
      font-size: 18px;
      color: rgba(255,255,255,0.85);
      margin-top: 8px;
    }

    /* ─── OPT-IN ─── */
    #optin {
      background: var(--navy);
      padding: 90px 0;
    }
    .optin-wrap {
      max-width: 680px;
      margin: 0 auto;
      background: var(--navy2);
      border: 1px solid rgba(22,103,232,0.3);
      border-radius: 20px;
      padding: 56px 52px;
      text-align: center;
    }
    .optin-wrap h2 {
      font-size: clamp(24px, 3vw, 36px);
      font-weight: 900;
      color: #fff;
      line-height: 1.2;
      margin-bottom: 14px;
    }
    .optin-wrap > p {
      font-size: 16px;
      color: var(--muted);
      line-height: 1.7;
      margin-bottom: 36px;
    }
    .optin-form {
      display: flex;
      flex-direction: column;
      gap: 16px;
      text-align: left;
    }
    .form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; }
    .form-group { display: flex; flex-direction: column; gap: 7px; }
    .form-group label {
      font-size: 13px;
      font-weight: 700;
      color: rgba(255,255,255,0.70);
      letter-spacing: 0.3px;
    }
    .form-group input,
    .form-group select {
      padding: 14px 18px;
      border: 1.5px solid rgba(255,255,255,0.10);
      border-radius: 6px;
      font-family: 'Manrope', sans-serif;
      font-size: 15px;
      color: #fff;
      background: rgba(255,255,255,0.05);
      outline: none;
      transition: border-color .2s;
      -webkit-appearance: none;
    }
    .form-group input:focus,
    .form-group select:focus { border-color: var(--azure); }
    .form-group input::placeholder { color: rgba(255,255,255,0.25); }
    .form-group select option { background: var(--navy2); color: #fff; }
    .optin-form .btn-primary { width: 100%; text-align: center; font-size: 17px; padding: 20px; margin-top: 4px; }
    .form-privacy { font-size: 12px; color: rgba(255,255,255,0.30); text-align: center; margin-top: 10px; }

    /* ─── PRICING ─── */
    #pricing {
      background: var(--charcoal);
      padding: 90px 0;
    }
    .pricing-grid {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 24px;
      max-width: 820px;
      margin: 0 auto;
    }
    .pc {
      background: var(--navy2);
      border: 1px solid rgba(255,255,255,0.07);
      border-radius: 16px;
      padding: 44px 40px;
      text-align: center;
      transition: border-color .2s;
    }
    .pc.active {
      border-color: rgba(22,103,232,0.5);
      position: relative;
    }
    .pc.active::before {
      content: 'MOST POPULAR';
      position: absolute;
      top: -12px; left: 50%;
      transform: translateX(-50%);
      background: var(--azure);
      color: #fff;
      font-size: 10px;
      font-weight: 800;
      letter-spacing: 1.5px;
      padding: 4px 16px;
      border-radius: 20px;
    }
    .pc-name { font-size: 18px; font-weight: 800; color: #fff; margin-bottom: 6px; }
    .pc-sub { font-size: 13px; color: var(--muted); margin-bottom: 24px; }
    .pc-price {
      font-size: 58px;
      font-weight: 900;
      color: var(--white);
      line-height: 1;
      margin-bottom: 6px;
    }
    .pc-price span { font-size: 26px; vertical-align: top; line-height: 2.1; }
    .pc-period { font-size: 14px; color: var(--muted); margin-bottom: 6px; }
    .pc-save { font-size: 13px; color: var(--gold); font-weight: 700; margin-bottom: 28px; min-height: 20px; }
    .pc-includes {
      list-style: none;
      text-align: left;
      background: rgba(255,255,255,0.04);
      border-radius: 8px;
      padding: 20px 22px;
      margin-bottom: 28px;
    }
    .pc-includes li {
      font-size: 14px;
      color: rgba(255,255,255,0.75);
      padding: 6px 0 6px 22px;
      position: relative;
    }
    .pc-includes li::before {
      content: '✓';
      position: absolute; left: 0;
      color: var(--azure);
      font-weight: 700;
    }
    .pc .btn-primary { width: 100%; font-size: 16px; }
    .pc-guarantee {
      font-size: 12px;
      color: rgba(255,255,255,0.30);
      margin-top: 16px;
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 6px;
    }

    /* ─── FINAL CTA ─── */
    #final-cta {
      background: var(--azure);
      padding: 90px 0;
      text-align: center;
      position: relative;
      overflow: hidden;
    }
    #final-cta::before {
      content: '';
      position: absolute;
      top: 50%; left: 50%;
      transform: translate(-50%, -50%);
      width: 700px; height: 700px;
      background: radial-gradient(circle, rgba(255,255,255,0.08) 0%, transparent 65%);
      pointer-events: none;
    }
    #final-cta h2 {
      font-size: clamp(30px, 4vw, 50px);
      font-weight: 900;
      color: #fff;
      line-height: 1.15;
      margin-bottom: 20px;
      position: relative;
    }
    #final-cta p {
      font-size: 18px;
      color: rgba(255,255,255,0.80);
      max-width: 540px;
      margin: 0 auto 40px;
      line-height: 1.7;
      position: relative;
    }
    .final-ctas {
      display: flex;
      gap: 16px;
      justify-content: center;
      flex-wrap: wrap;
      position: relative;
    }
    #final-cta .btn-primary {
      background: #fff;
      color: var(--azure);
    }
    #final-cta .btn-primary:hover { background: rgba(255,255,255,0.92); }
    #final-cta .btn-ghost {
      border-color: rgba(255,255,255,0.7);
      color: #fff;
    }

    /* ─── FOOTER ─── */
    footer {
      background: var(--charcoal);
      border-top: 1px solid rgba(255,255,255,0.06);
      padding: 36px 0;
      text-align: center;
    }
    footer p { font-size: 13px; color: rgba(255,255,255,0.25); }
    footer a { color: rgba(255,255,255,0.40); text-decoration: none; }
    footer a:hover { color: var(--azure); }

    /* ─── HAMBURGER ─── */
    .hamburger {
      display: none;
      flex-direction: column;
      gap: 5px;
      cursor: pointer;
      background: none;
      border: none;
      padding: 4px;
    }
    .hamburger span {
      display: block;
      width: 24px;
      height: 2px;
      background: #fff;
      border-radius: 2px;
      transition: all .3s;
    }
    .hamburger.open span:nth-child(1) { transform: translateY(7px) rotate(45deg); }
    .hamburger.open span:nth-child(2) { opacity: 0; }
    .hamburger.open span:nth-child(3) { transform: translateY(-7px) rotate(-45deg); }
    .mobile-menu {
      display: none;
      position: fixed;
      inset: 0;
      background: #1D2027;
      z-index: 99;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      gap: 32px;
    }
    .mobile-menu.open { display: flex; }
    .mobile-menu a {
      font-size: 22px;
      font-weight: 700;
      color: #fff;
      text-decoration: none;
      letter-spacing: 1px;
    }
    .mobile-menu a:hover { color: var(--azure); }

    /* ─── RESPONSIVE: TABLET ─── */
    @media (max-width: 960px) {
      .hero-inner { grid-template-columns: 1fr; }
      .hero-panel { display: none; }
      .stats-grid { grid-template-columns: repeat(2, 1fr); }
      .about-inner { grid-template-columns: 1fr; }
      .about-photo { display: none; }
      .services-grid { grid-template-columns: 1fr 1fr; }
      .training-grid { grid-template-columns: 1fr 1fr; }
      .modules-grid { grid-template-columns: 1fr 1fr; }
      .pain-grid { grid-template-columns: 1fr 1fr; }
      .testi-grid { grid-template-columns: 1fr; }
      .nlca-inner { grid-template-columns: 1fr; padding: 40px 32px; }
    }
    /* ─── PLAN SELECTOR ─── */
    .plan-option {
      cursor: pointer;
      position: relative;
      transition: border-color .2s, background .2s, transform .15s;
      border: 2px solid rgba(255,255,255,0.08) !important;
      user-select: none;
    }
    .plan-option:hover { border-color: rgba(22,103,232,0.5) !important; transform: translateY(-2px); }
    .plan-option.selected {
      border-color: var(--azure) !important;
      background: rgba(22,103,232,0.12) !important;
    }
    .plan-check {
      position: absolute;
      top: 10px; right: 12px;
      width: 20px; height: 20px;
      border-radius: 50%;
      background: rgba(255,255,255,0.08);
      border: 2px solid rgba(255,255,255,0.2);
      display: flex; align-items: center; justify-content: center;
      font-size: 10px;
      color: transparent;
      transition: all .2s;
    }
    .plan-option.selected .plan-check {
      background: var(--azure);
      border-color: var(--azure);
      color: #fff;
    }

    /* ─── MODAL ─── */
    .modal-overlay {
      display: none;
      position: fixed;
      inset: 0;
      background: rgba(4,4,23,0.88);
      backdrop-filter: blur(8px);
      z-index: 1000;
      align-items: center;
      justify-content: center;
      padding: 24px;
    }
    .modal-overlay.open { display: flex; }
    .modal-box {
      background: var(--navy2);
      border: 1px solid rgba(22,103,232,0.35);
      border-radius: 20px;
      padding: 48px 44px;
      max-width: 520px;
      width: 100%;
      position: relative;
      animation: modalIn .25s ease;
    }
    @keyframes modalIn {
      from { opacity: 0; transform: translateY(20px) scale(0.97); }
      to   { opacity: 1; transform: translateY(0) scale(1); }
    }
    .modal-close {
      position: absolute;
      top: 16px; right: 20px;
      background: none;
      border: none;
      color: rgba(255,255,255,0.4);
      font-size: 22px;
      cursor: pointer;
      line-height: 1;
      transition: color .2s;
    }
    .modal-close:hover { color: #fff; }
    .modal-tag {
      font-size: 11px;
      font-weight: 700;
      letter-spacing: 2px;
      text-transform: uppercase;
      color: var(--azure);
      margin-bottom: 12px;
    }
    .modal-box h3 {
      font-size: 26px;
      font-weight: 900;
      color: #fff;
      margin-bottom: 8px;
      line-height: 1.2;
    }
